// Exemplo conceitual de composição (independente do renderizador)
// A ideia é gerar uma árvore de blocos determinística.

function buildMinimalDoc(input) {
  return [
    { type: 'heading', level: 1, text: input.title },
    { type: 'paragraph', text: `Versão: ${input.version}` },
    { type: 'list', items: input.checks },
    { type: 'pagebreak' },
    { type: 'heading', level: 2, text: 'Trecho de código' },
    { type: 'code', lang: 'js', content: input.snippet }
  ];
}

const doc = buildMinimalDoc({
  title: 'Teste técnico',
  version: '1.0.0',
  checks: ['Fontes incorporadas', 'Unicode ok', 'Quebras previsíveis'],
  snippet: "console.log('PDF determinístico');"
});

console.log(doc);
